#include <iostream>
#include <climits>
using namespace std;
int main() {
    int a, b;
    cin >> a >> b;
    long long product = (long long)a * b;
    if (product > INT_MAX || product < INT_MIN) {
        cout << "Overflow! Result (long long): " << product << endl;
    } else {
        cout << "Fits in int: " << (int)product << endl;
    }
    return 0;
